import { useEffect, type RefObject } from 'react';
import { isStandalone } from '../../dev/isStandalone';

const MIN_SHELL_PX = 280;

/**
 * Voucher form shell — embedded: flex fill (parent `.mainEmbedded` height 100vh border-box).
 * Standalone: chiều cao = viewport còn lại.
 */
export function useVoucherFormShellHeight(shellRef: RefObject<HTMLElement | null>): void {
  useEffect(() => {
    const shell = shellRef.current;
    if (!shell) return undefined;

    const apply = () => {
      const contentHost = shell.closest('[class*="content"]');
      if (contentHost instanceof HTMLElement) {
        contentHost.scrollTop = 0;
      }

      if (!isStandalone) {
        shell.style.height = '';
        shell.style.maxHeight = '';
        shell.style.flex = '1';
        shell.style.minHeight = '0';
        return;
      }

      const top = Math.max(0, shell.getBoundingClientRect().top);
      const height = Math.max(MIN_SHELL_PX, window.innerHeight - top);
      shell.style.flex = 'none';
      shell.style.height = `${height}px`;
      shell.style.maxHeight = `${height}px`;
    };

    const timer = window.setTimeout(() => {
      apply();
      window.requestAnimationFrame(apply);
    }, 0);

    window.addEventListener('resize', apply);
    window.addEventListener('linm:nav:toggle-mobile', apply);
    window.addEventListener('linm:nav:topbar-autohide', apply);

    let ro: ResizeObserver | undefined;
    if (typeof ResizeObserver !== 'undefined') {
      ro = new ResizeObserver(() => apply());
      const contentEl = shell.closest('[class*="content"]');
      if (contentEl instanceof HTMLElement) ro.observe(contentEl);
    }

    return () => {
      clearTimeout(timer);
      window.removeEventListener('resize', apply);
      window.removeEventListener('linm:nav:toggle-mobile', apply);
      window.removeEventListener('linm:nav:topbar-autohide', apply);
      ro?.disconnect();
      shell.style.height = '';
      shell.style.maxHeight = '';
      shell.style.flex = '';
      shell.style.minHeight = '';
    };
  }, [shellRef]);
}
